      "type": "object",
      "properties": {
        "matrix_name": {
          "type": "string",
          "description": "The key or name of the synthesis matrix to retrieve."
        }
      },
      "required": [
        "matrix_name"
      ]
    },
    "example_output": {
      "matrix_entries": [
        "ID_001",
        "ID_002"
