      "status": "Published",
      "is_version_of_record": true
    }
  },
  "evaluate_aacods_score": {
    "description": "Performs a quality appraisal of a source based on AACODS standards (Authority, Accuracy, Coverage, Objectivity, Date, Significance).",
    "parameters": {
      "type": "object",
      "properties": {
        "paper_id": {
          "type": "string"
        }
      },
      "required": [
        "paper_id"
      ]
    },
    "example_output": {
      "score": 5,
      "passed_threshold": true
    }
  },
  "update_workspace_matrix": {
    "description": "Finalizes the synthesis matrix by updating the evidence list and the Grey_Yield_Ratio metric.",
    "parameters": {
      "type": "object",
      "properties": {
        "matrix_name": {
          "type": "string"
        },
        "final_evidence_list": {
          "type": "array",
          "items": {
